import { createContext, useReducer, useContext, useMemo } from "react";
import {getSearch} from "./utils";

const tableContext = createContext()
const initialState = {
  tableData: null,
  transformedData: null,
  searchedData: null,
  searchText: '',
  headerList: [ 'id', 'title', 'price', 'rating', 'reviews', 'brand', 'category' ]
}
const ACTIONS = {
    SET_TABLE_DATA: 'SET_TABLE_DATA',
    ON_SEARCH: 'ON_SEARCH'
}

function reducer (state = initialState, action) {
    switch(action.type) {
        case ACTIONS.SET_TABLE_DATA: {
            console.log('state', state)
            return {
                ...state,
                tableData: [...(state.tableData || []), ...action.data.tableData],
                transformedData: action.data.tableData.map(item => {
                    const { id, title, price, rating, reviews, brand, category, ...rest} = item
                    return { id, title, price, rating, reviews: reviews.length, brand, category}
                }),
                searchedData: action.data.tableData.map(item => {
                    const { id, title, price, rating, reviews, brand, category, ...rest} = item
                    return { id, title, price, rating, reviews: reviews.length, brand, category}
                })
            }
        }
        case ACTIONS.ON_SEARCH: {
            console.log('>>>', state.transformedData.filter(item => getSearch(item?.title, action.data.searchText) || getSearch(item?.brand, action.data.searchText) || getSearch(item?.category, action.data.searchText)))
            return {
                ...state,
                searchText: action.data.searchText,
                searchedData: state.transformedData.filter(item => getSearch(item?.title, action.data.searchText) || getSearch(item?.brand, action.data.searchText) || getSearch(item?.category, action.data.searchText))
            }
        }
    }
}
function TableProvider({children, tableData}) {
 const [state, dispatch] = useReducer(reducer, initialState)

 const setTableData = tableData => dispatch({
    type: ACTIONS.SET_TABLE_DATA,
    data: {
        tableData
    }
 })
 const onSearchHandler = searchText => dispatch({
    type: ACTIONS.ON_SEARCH,
    data: {
        searchText
    }
 })
 const contextValue = {
    setTableData,
    onSearchHandler,
    ...state
 }
 return (
 <tableContext.Provider value={contextValue}>
  {children}
 </tableContext.Provider>
 )
}
export default TableProvider

export function useTableContext() {
  return useContext(tableContext)
}
